import React, { useState, useEffect } from 'react';
import { db } from '../../utils/firebase';
import { doc, getDoc, collection, getDocs, addDoc } from 'firebase/firestore';
import { Shield, MapPin, PlusCircle, Trash2, Layers } from 'lucide-react';

export default function MaterialDept() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [adminId, setAdminId] = useState('');
  const [password, setPassword] = useState('');
  
  // DYNAMIC STATE
  const [assignedArea, setAssignedArea] = useState(''); 
  const [logisticsSector, setLogisticsSector] = useState('');
  const [workersList, setWorkersList] = useState([]);
  
  // FORM STATES
  const [workerName, setWorkerName] = useState('');
  const [workerLogin, setWorkerLogin] = useState('');
  const [workerPassword, setWorkerPassword] = useState('');

  const styles = {
    layout: { padding: '24px', backgroundColor: '#F8FAFC', minHeight: '100vh', fontFamily: 'sans-serif' },
    authWrapper: { minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', backgroundColor: '#0B1220' },
    authCard: { backgroundColor: '#FFFFFF', padding: '35px', borderRadius: '12px', width: '400px', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)' },
    metaHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', backgroundColor: '#0F172A', padding: '16px 24px', borderRadius: '12px', color: '#FFFFFF', marginBottom: '24px' },
    input: { padding: '10px 14px', border: '1px solid #CBD5E1', borderRadius: '8px', width: '100%', marginBottom: '10px' },
    button: { padding: '10px 20px', backgroundColor: '#10B981', color: '#FFFFFF', border: 'none', borderRadius: '8px', cursor: 'pointer', width: '100%' },
    card: { backgroundColor: '#fff', padding: '24px', borderRadius: '12px', border: '1px solid #E2E8F0', marginBottom: '20px' }
  };

  // 1. AUTH GATE & DYNAMIC FETCHING
  const handleAdminAuthGate = async (e) => {
    e.preventDefault();
    try {
      const vendorRef = doc(db, "vendors", adminId.trim());
      const vendorSnap = await getDoc(vendorRef);

      if (vendorSnap.exists()) {
        const data = vendorSnap.data();
        if (String(data.password) === String(password)) {
          // Yahan data.targetArea se value utha rahe hain
          setAssignedArea(data.targetArea || 'No Area Assigned');
          setLogisticsSector(data.logisticsSectorType || 'General');
          setIsAuthenticated(true);
        } else {
          alert("Invalid Credentials.");
        }
      } else {
        alert("Vendor ID not found.");
      }
    } catch (err) {
      console.error(err);
      alert("Error logging in.");
    }
  };

  // 2. DYNAMIC WORKER FETCHING
  useEffect(() => {
    if (isAuthenticated && assignedArea !== 'No Area Assigned') {
      const fetchWorkers = async () => {
        // Yahan path dynamic hai, 'platform no 1' hardcoded nahi hai
        const q = collection(db, "vendors", assignedArea.trim(), "workers");
        const snap = await getDocs(q);
        setWorkersList(snap.docs.map(d => ({ id: d.id, ...d.data() })));
      };
      fetchWorkers();
    }
  }, [isAuthenticated, assignedArea]);

  // 3. ADD WORKER
  const handleAddWorker = async () => {
    if (!assignedArea || assignedArea === 'No Area Assigned') return alert("Area not assigned!");
    
    await addDoc(collection(db, "vendors", assignedArea.trim(), "workers"), {
      workerName, loginId: workerLogin, password: workerPassword
    });
    alert("Worker Added Successfully!");
    window.location.reload(); 
  };

  if (!isAuthenticated) {
    return (
      <div style={styles.authWrapper}>
        <div style={styles.authCard}>
          <h2 style={{ textAlign: 'center', marginBottom: '20px' }}>Material Storage Dept</h2>
          <form onSubmit={handleAdminAuthGate}>
            <input style={styles.input} placeholder="Admin ID" onChange={(e) => setAdminId(e.target.value)} />
            <input style={styles.input} type="password" placeholder="Password" onChange={(e) => setPassword(e.target.value)} />
            <button style={styles.button} type="submit">Verify & Unlock Panel</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.layout}>
      <div style={styles.metaHeader}>
        <h1>Material Storage Staff Management</h1>
        <div style={{ display: 'flex', gap: '15px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <MapPin size={18} /> Area: <b>{assignedArea}</b>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <Shield size={18} /> Sector: <b>{logisticsSector}</b>
          </div>
        </div>
      </div>

      <div style={styles.card}>
        <h3>Deploy Operators at [{assignedArea}]</h3>
        <input style={styles.input} placeholder="Name" onChange={(e) => setWorkerName(e.target.value)} />
        <input style={styles.input} placeholder="Login ID" onChange={(e) => setWorkerLogin(e.target.value)} />
        <input style={styles.input} type="password" placeholder="Password" onChange={(e) => setWorkerPassword(e.target.value)} />
        <button style={styles.button} onClick={handleAddWorker}>Add Worker</button>
      </div>

      <div style={styles.card}>
        <h3>Active Operators Registry</h3>
        {workersList.map(w => (
          <div key={w.id} style={{ padding: '10px', borderBottom: '1px solid #eee' }}>
             {w.workerName} - ID: {w.loginId}
          </div>
        ))}
      </div>
    </div>
  );
}
